def A097610row(n: int) -> list[int]:
    row = [0] * (n + 1); row[n] = 1
    for k in range(n, 1, -2):
        num = 4 * k * (k - 1)
        den = (n - k + 2) * (n - k + 4)
        row[k - 2] = (row[k] * num) // den
    return row
